SELECT 
FROM homework h
LEFT JOIN class_entity c ON h.class_id = c.id
LEFT JOIN sys_user u ON h.teacher_id = u.id
WHERE h.is_deleted = 0

    AND h.class_id = #{classId}


    AND h.teacher_id = #{teacherId}


    AND h.subject = #{subject}


    AND h.status = #{status}

ORDER BY h.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM homework h
WHERE h.is_deleted = 0

    AND h.class_id = #{classId}


    AND h.teacher_id = #{teacherId}


    AND h.subject = #{subject}


    AND h.status = #{status}
